def now_utc():
    return datetime.utcnow()


def dt_to_str(dt: datetime) -> str:
    return dt.replace(microsecond=0).isoformat() + "Z"


def str_to_dt(s: str) -> datetime:
    if s.endswith("Z"):
        s = s[:-1]
    return datetime.fromisoformat(s)


def constant_time_eq(a: str, b: str) -> bool:
    return hmac.compare_digest(a.encode("utf-8"), b.encode("utf-8"))


def pbkdf2_hash(password: str, salt: bytes, iterations: int = 200_000) -> bytes:
    return hashlib.pbkdf2_hmac("sha256", (password + PASSWORD_PEPPER).encode("utf-8"), salt, iterations)


def verify_password(password: str, salt: bytes, expected_hash: bytes) -> bool:
    cand = pbkdf2_hash(password, salt)
    return hmac.compare_digest(cand, expected_hash)


def random_b32_secret(num_bytes: int = 20) -> str:
    raw = secrets.token_bytes(num_bytes)
    return base64.b32encode(raw).decode("utf-8").strip("=")


def totp(secret_b32: str, for_time: int, digits: int = MFA_TOTP_DIGITS, period: int = MFA_TOTP_PERIOD) -> str:
    padding = "=" * ((8 - (len(secret_b32) % 8)) % 8)
    key = base64.b32decode(secret_b32.upper() + padding)
    counter = int(for_time // period)
    msg = counter.to_bytes(8, "big")
    hm = hmac.new(key, msg, hashlib.sha1).digest()
    off = hm[-1] & 0x0F
    code_int = (int.from_bytes(hm[off:off + 4], "big") & 0x7FFFFFFF) % (10 ** digits)
    return str(code_int).zfill(digits)


def verify_totp(code: str, secret_b32: str) -> bool:
    if not code or not code.isdigit():
        return False
    code = code.strip()
    t = int(time.time())
    for w in range(-MFA_TOTP_SKEW_WINDOWS, MFA_TOTP_SKEW_WINDOWS + 1):
        if constant_time_eq(code, totp(secret_b32, t + w * MFA_TOTP_PERIOD)):
            return True
    return False


def create_user(username: str, password: str) -> int:
    db = get_db()
    salt = secrets.token_bytes(16)
    pwd_hash = pbkdf2_hash(password, salt)
