    created_at = dt_to_str(now_utc())
    db.execute(
        "INSERT INTO users(username, password_salt, password_hash, mfa_secret_b32, created_at) VALUES(?,?,?,?,?)",
        (username, salt, pwd_hash, mfa_secret, created_at),
    )
    db.commit()
    return db.execute("SELECT id FROM users WHERE username=?", (username,)).fetchone()["id"]


