def create_login_session(user_id: int, ip: str, ua: str, mfa_required: bool = True):
    db = get_db()
    token = secrets.token_urlsafe(32)
    created = now_utc()
    expires = created + timedelta(seconds=SESSION_MAX_AGE_SECONDS)
    pwd_verified = created
    mfa_due = created + timedelta(seconds=MFA_GRACE_SECONDS)
    db.execute(
        """
        INSERT INTO login_sessions(user_id, session_token, created_at, expires_at, password_verified_at, mfa_verified_at, mfa_required, mfa_due_at, last_ip, last_ua)
        VALUES(?,?,?,?,?,?,?,?,?,?)
        """,
        (
            user_id,
            token,
            dt_to_str(created),
            dt_to_str(expires),
            dt_to_str(pwd_verified),
            None,
            1 if mfa_required else 0,
            dt_to_str(mfa_due),
            ip,
            ua,
        ),
    )
    db.commit()
    return token


