@app.route("/login", methods=["POST"])
def login():
    clean_expired_sessions()
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    if not username or not password:
        return jsonify({"error": "invalid_request"}), 400

    user = get_user_by_username(username)
    if not user:
        time.sleep(0.2)
        return jsonify({"error": "invalid_credentials"}), 401

    if not verify_password(password, user["password_salt"], user["password_hash"]):
        time.sleep(0.2)
        return jsonify({"error": "invalid_credentials"}), 401

    token = create_login_session(
        user_id=user["id"],
        ip=request.headers.get("X-Forwarded-For", request.remote_addr) or "",
        ua=request.headers.get("User-Agent", "") or "",
        mfa_required=True,
    )
    session.permanent = True
    session["session_token"] = token

    next_url = data.get("next") or request.args.get("next") or url_for("protected", _external=True)
    verify_url = url_for("verify_mfa", _external=True)
    resp = make_response(redirect(verify_url))
    resp.headers["X-Next-URL"] = next_url
    return resp


@app.route("/verify-mfa", methods=["GET", "POST"])
def verify_mfa():
    clean_expired_sessions()
